    "\n",
    "cap = cv2.VideoCapture(0)\n",
    "\n",
    "while True:\n",
    "    ret, frame = cap.read()\n",
    "    if not ret:\n",
    "        break\n",
    "\n",
    "    cv2.putText(\n",
    "        frame,\n",
    "        \"OpenCV Live Overlay\",\n",
    "        (30, 40),                     # position (x, y)\n",
    "        cv2.FONT_HERSHEY_SIMPLEX,     # font\n",
    "        1,                            # font scale\n",
    "        (0,0, 255),                  # color (BGR)\n",
